mapper.select:
select t3.amount,count(t3.amount) as countNum from biz_wxpay_bill t2 left join biz_accident t on t.id=t2.accid left join biz_wx_pay_record t3 on t3.bill_id=t2.id where t.address like CONCAT('%',#{city},'%') and t.`status`='2' and t2.status='0' and (t3.amount='1.88' or t3.amount='5' or t3.amount='10')
and t3.payment_time>=#{startTime}
and t3.payment_time <= #{endTime}
GROUP BY t3.amount

select t1.account,t2.`name` as identity,t1.name as userName ,t1.sfkf,( select count(1) from biz_wxpay_bill t188 left join biz_wx_pay_record t1883 on t1883.bill_id=t188.id left JOIN biz_push_record t1884 on t1884.accid=t188.accid where t188.`status`='0' and t1883.amount='1.88' and t1884.account=t1.account
and (t1883.create_time between #{startTime} and #{endTime})
)amount188,( select count(1) from biz_wxpay_bill t188 left join biz_wx_pay_record t1883 on t1883.bill_id=t188.id left JOIN biz_push_record t1884 on t1884.accid=t188.accid where t188.`status`='0' and t1883.amount='5' and t1884.account=t1.account
and (t1883.create_time between #{startTime} and #{endTime})
)amount5,( select count(1) from biz_wxpay_bill t188 left join biz_wx_pay_record t1883 on t1883.bill_id=t188.id left JOIN biz_push_record t1884 on t1884.accid=t188.accid where t188.`status`='0' and t1883.amount='10' and t1884.account=t1.account
and (t1883.create_time between #{startTime} and #{endTime})
)amount10,t3.simplename, ( select count(1) from biz_open_claim tboc where t1.account=tboc.claimer and tboc.`status`='3'
and (tboc.createtime between #{startTime} and #{endTime})
) openClaimNum, ROUND(( select sum(rebate_for_company) from biz_open_claim tboc where t1.account=tboc.claimer and tboc.`status`='3'
and (tboc.createtime between #{startTime} and #{endTime})
) ,2) as openClaimSum from sys_user t1 left join sys_role t2 on t1.roleid=t2.id left join sys_dept t3 on t3.id=t1.deptid where (t2.id=6 or t2.id=7 or t2.id=8)
and t3.simplename like CONCAT('%',#{department},'%')
and t1.name like CONCAT('%',#{name},'%')
